
import base64
import zipfile
import io

# The PPTX string from officeTemplates.ts (manually copied from previous view_file)
pptx_str = ''

try:
    data = base64.b64decode(pptx_str)
    with zipfile.ZipFile(io.BytesIO(data)) as z:
        print("Valid Zip. Contents:")
        for name in z.namelist():
            print(f" - {name}")
except Exception as e:
    print(f"Error: {e}")
